CREATE TABLE notification_record(id BIGINT PRIMARY KEY AUTO_INCREMENT,request_id VARCHAR(80) NOT NULL UNIQUE,user_id VARCHAR(64) NOT NULL,email VARCHAR(320),subject VARCHAR(255) NOT NULL,body TEXT NOT NULL,status VARCHAR(32) NOT NULL,read_flag BOOLEAN NOT NULL DEFAULT FALSE,failure_reason VARCHAR(255),created_at TIMESTAMP(6) NOT NULL,sent_at TIMESTAMP(6));CREATE INDEX idx_notification_user ON notification_record(user_id,read_flag,created_at);
